graph TD;
  A[b₀: Initial Reference Bit] -->|Compare| B[b₁: Incoming Bit];
  B -->|b₀ ⋄ b₁| C[b₂: Comparison Output];
  C -->|b₁ ⋄ b₂| D[b₃];
  D -->|b₂ ⋄ b₃| E[b₄];
  C --> T["Triad: (b₀, b₁, b₂)"];
  D --> U["Triad: (b₁, b₂, b₃)"];
  T -->|Δℂ ≥ I_N| V["Coherence Validated"];
  V -->|→| W["Recursive Braid Holds"];
  classDef highlight fill=#f9f,stroke=#333,stroke-width=2px;
  T,U,V,W:::highlight

math:
f_{\text{Gate16}}(S_1, S_2) := \begin{cases}
1 & \text{if } S_1 \neq S_2 \land \Delta \mathcal{C}(S_1, S_2) \geq I_N \\
0 & \text{if } S_1 = S_2 \land \Delta \mathcal{C}(S_1, S_2) \geq I_N \\
\text{undefined} & \text{if } \Delta \mathcal{C} < I_N
\end{cases}
